import{_ as a,c as e,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"更新履歴: バージョン進化と新機能 | Plannotator","description":"Plannotatorのバージョン履歴と新機能リリースについて学習します。各バージョンの改善、バグ修正、コードレビュー、画像アノテーションなどの機能の進化を把握できます。","frontmatter":{"title":"更新履歴: バージョン進化と新機能 | Plannotator","sidebarTitle":"新機能を見る","subtitle":"更新履歴: バージョン進化と新機能 | Plannotator","description":"Plannotatorのバージョン履歴と新機能リリースについて学習します。各バージョンの改善、バグ修正、コードレビュー、画像アノテーションなどの機能の進化を把握できます。","order":6},"headers":[],"relativePath":"ja/backnotprop/plannotator/changelog/index.md","filePath":"ja/backnotprop/plannotator/changelog/index.md"}'),n={name:"ja/backnotprop/plannotator/changelog/index.md"};function d(l,t,i,s,c,p){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="更新履歴" tabindex="-1">更新履歴 <a class="header-anchor" href="#更新履歴" aria-label="Permalink to &quot;更新履歴&quot;">​</a></h1><p>この章では Plannotator のバージョン履歴、新機能リリース、バグ修正情報を記録し、プロジェクトの進化と最新動向を理解できるようにします。</p><h2 id="本章の内容" tabindex="-1">本章の内容 <a class="header-anchor" href="#本章の内容" aria-label="Permalink to &quot;本章の内容&quot;">​</a></h2><div class="grid-cards"><a href="./release-notes/" class="card"><h3>📋 バージョン履歴</h3><p>Plannotator の完全なバージョン履歴を確認します。各バージョンの新機能、改善、バグ修正が含まれます。コードレビュー、画像アノテーション、Obsidian/Bear 連携などの主要機能のリリースタイムラインを把握できます。</p></a></div><h2 id="読む際のヒント" tabindex="-1">読む際のヒント <a class="header-anchor" href="#読む際のヒント" aria-label="Permalink to &quot;読む際のヒント&quot;">​</a></h2><p>更新履歴は以下のシーンで読むことをお勧めします。</p><table tabindex="0"><thead><tr><th>シーン</th><th>お勧め</th></tr></thead><tbody><tr><td><strong>アップグレード前の確認</strong></td><td>対象バージョンの新機能と破壊的変更を確認する</td></tr><tr><td><strong>機能探索</strong></td><td>最新バージョンでどのような機能が追加されたかを理解する</td></tr><tr><td><strong>トラブルシューティング</strong></td><td>特定のバグが新しいバージョンで修正されているかを確認する</td></tr><tr><td><strong>バージョン互換性</strong></td><td>Plannotator と Claude Code/OpenCode のバージョン対応関係を確認する</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">最新版を維持する</p><p>定期的に更新履歴を確認し、新機能とセキュリティ修正を取得するために最新バージョンにアップグレードすることをお勧めします。</p></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>更新履歴の読み取りが完了したら、以下の操作ができます：</p><ul><li><a href="./../start/getting-started/">クイックスタート</a> に戻って基本操作を学ぶ</li><li><a href="./../faq/common-problems/">よくある問題</a> を見て使用中の問題を解決する</li><li><a href="./../appendix/api-reference/">API リファレンス</a> を読んですべての API エンドポイントを理解する</li></ul>',11)])])}const _=a(n,[["render",d]]);export{b as __pageData,_ as default};
